A converter from a **curl command to Python `requests`**: you paste "Copy as cURL" from DevTools/Burp and get a ready script with the method, headers, cookies and body. Then you tweak it for fuzzing/automation.

deps: stdlib. placeholders: `{{CURL}}` (the command as a string or via stdin).

```python
#!/usr/bin/env python3
# curl_to_python.py - ARS3NAL (GPL-3.0).
import argparse, shlex, sys, json

def parse(tokens):
    method, url, headers, data, cookies = "GET", "", {}, None, {}
    it = iter(range(len(tokens)))
    i = 0
    while i < len(tokens):
        t = tokens[i]
        if t in ("curl",):
            i += 1; continue
        if t in ("-X", "--request"):
            method = tokens[i+1]; i += 2; continue
        if t in ("-H", "--header"):
            k, _, v = tokens[i+1].partition(":")
            if k.lower() == "cookie":
                for c in v.split(";"):
                    ck, _, cv = c.strip().partition("=")
                    if ck: cookies[ck] = cv
            else:
                headers[k.strip()] = v.strip()
            i += 2; continue
        if t in ("-b", "--cookie"):
            for c in tokens[i+1].split(";"):
                ck, _, cv = c.strip().partition("=")
                if ck: cookies[ck] = cv
            i += 2; continue
        if t in ("-d", "--data", "--data-raw", "--data-binary", "--data-urlencode"):
            data = tokens[i+1]; method = "POST" if method == "GET" else method; i += 2; continue
        if t in ("-u", "--user", "-A", "--user-agent", "-e", "--referer"):
            if t in ("-A", "--user-agent"): headers["User-Agent"] = tokens[i+1]
            if t in ("-e", "--referer"): headers["Referer"] = tokens[i+1]
            i += 2; continue
        if t in ("--compressed", "-k", "--insecure", "-s", "--silent", "-i", "-L", "--location"):
            i += 1; continue
        if t.startswith("http"):
            url = t
        i += 1
    return method, url, headers, data, cookies

def emit(method, url, headers, data, cookies):
    lines = ["import requests", ""]
    lines.append(f"url = {url!r}")
    lines.append(f"headers = {json.dumps(headers, indent=4)}")
    if cookies:
        lines.append(f"cookies = {json.dumps(cookies, indent=4)}")
    if data is not None:
        lines.append(f"data = {data!r}")
    call = f"r = requests.request({method!r}, url, headers=headers"
    if cookies: call += ", cookies=cookies"
    if data is not None: call += ", data=data"
    call += ", verify=False)"
    lines += ["", call, "print(r.status_code)", "print(r.text[:500])"]
    return "\n".join(lines)

def main():
    ap = argparse.ArgumentParser(description="ARS3NAL curl -> requests")
    ap.add_argument("curl", nargs="*", help="curl command (or pipe via stdin)")
    a = ap.parse_args()
    raw = " ".join(a.curl) if a.curl else sys.stdin.read()
    tokens = shlex.split(raw.replace("\\\n", " "))
    print(emit(*parse(tokens)))

if __name__ == "__main__":
    main()
```

Run:
```bash
python3 curl_to_python.py "curl -X POST https://t/api -H 'Cookie: s=1' -d 'a=b'"
pbpaste | python3 curl_to_python.py      # from the clipboard (Copy as cURL)
```
